class SQSWorker:
    """SQS message worker with injection prevention."""

    def __init__(
        self,
        queue_url: str,
        region_name: str = "us-east-1",
        max_messages: int = 10,
        wait_time_seconds: int = 20,
        visibility_timeout: int = 300,
        max_retries: int = 3,
        handler_registry: MessageHandlerRegistry = handler_registry,
        aws_access_key_id: Optional[str] = None,
        aws_secret_access_key: Optional[str] = None,
    ):
        self.queue_url = queue_url
        self.max_messages = min(max_messages, 10)  # SQS max is 10
        self.wait_time_seconds = min(wait_time_seconds, 20)  # SQS max is 20
        self.visibility_timeout = visibility_timeout
        self.max_retries = max_retries
        self.handler_registry = handler_registry
        self._running = False

        session_kwargs = {"region_name": region_name}
        if aws_access_key_id and aws_secret_access_key:
            session_kwargs["aws_access_key_id"] = aws_access_key_id
            session_kwargs["aws_secret_access_key"] = aws_secret_access_key

        self.sqs_client = boto3.client("sqs", **session_kwargs)

    def _parse_and_validate_message(self, sqs_message: dict) -> ProcessedMessage:
        """Parse, sanitize, and validate an SQS message."""
        message_id = sqs_message.get("MessageId", "unknown")
        receipt_handle = sqs_message.get("ReceiptHandle", "")
        raw_body = sqs_message.get("Body", "")

        # Step 1: Parse JSON safely with size limit
        MAX_BODY_SIZE = 256 * 1024  # 256 KB (SQS max is 256 KB)
        if len(raw_body) > MAX_BODY_SIZE:
            raise MessageValidationError(f"Message body exceeds maximum size of {MAX_BODY_SIZE} bytes")

        try:
            body = json.loads(raw_body)
        except (json.JSONDecodeError, TypeError) as e:
            raise MessageValidationError(f"Invalid JSON in message body: {e}")

        if not isinstance(body, dict):
            raise MessageValidationError(f"Message body must be a JSON object, got {type(body).__name__}")

        # Step 2: Extract and validate message type (whitelist approach)
        raw_type = body.get("message_type")
        if raw_type is None:
            raise MessageValidationError("Missing 'message_type' field")

        if not isinstance(raw_type, str):
            raise MessageValidationError(f"'message_type' must be a string, got {type(raw_type).__name__}")

        message_type = MessageValidator.validate_message_type(raw_type)

        # Step 3: Extract and sanitize payload
        raw_payload = body.get("payload")
        if raw_payload is None:
            raise MessageValidationError("Missing 'payload' field")

        if not isinstance(raw_payload, dict):
            raise MessageValidationError(f"'payload' must be a dict, got {type(raw_payload).__name__}")

        # Sanitize all values in the payload
        sanitized_payload = MessageSanitizer.sanitize_dict(raw_payload, "payload")

        # Step 4: Validate payload schema
        MessageValidator.validate_payload_schema(message_type, sanitized_payload)

        # Step 5: Validate payload content
        MessageValidator.validate_payload_content(message_type, sanitized_payload)

        return ProcessedMessage(
            message_type=message_type,
            payload=sanitized_payload,
            message_id=message_id,
            receipt_handle=receipt_handle,
        )

    def _process_message(self, sqs_message: dict) -> bool:
        """Process a single SQS message. Returns True if successful."""
        message_id = sqs_message.get("MessageId", "unknown")

        try:
            # Validate and sanitize
            processed = self._parse_and_validate_message(sqs_message)
            logger.info(f"Processing message {processed.message_id} of type {processed.message_type.value}")

            # Get handler from registry (no dynamic dispatch)
            handler = self.handler_registry.get_handler(processed.message_type)
            if handler is None:
                logger.error(f"No handler registered for message type: {processed.message_type.value}")
                return False

            # Execute handler
            result = handler(processed.payload)
            logger.info(f"Message {processed.message_id} processed successfully: {result}")

            # Delete message from queue on success
            self._delete_message(processed.receipt_handle)
            return True

        except MessageValidationError as e:
            logger.warning(f"Message {message_id} validation failed: {e}")
            # Delete invalid messages to prevent poison pill scenario
            # In production, you might want to send to a dead-letter queue instead
            receipt_handle = sqs_message.get("ReceiptHandle", "")
            if receipt_handle:
                self._move_to_dlq_or_delete(sqs_message, str(e))
            return False

        except Exception as e:
            logger.error(f"Error processing message {message_id}: {e}", exc_info=True)
            # Message will become visible again after visibility timeout
            return False

    def _delete_message(self, receipt_handle: str) -> None:
        """Delete a message from the queue."""
        try:
            self.sqs_client.delete_message(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle,
            )
        except Exception as e:
            logger.error(f"Failed to delete message: {e}")

    def _move_to_dlq_or_delete(self, sqs_message: dict, error_reason: str) -> None:
        """Move invalid message to DLQ or delete it."""
        receipt_handle = sqs_message.get("ReceiptHandle", "")
        message_id = sqs_message.get("MessageId", "unknown")

        logger.warning(
            f"Removing invalid message {message_id} from queue. Reason: {error_reason}"
        )
        # In production, you'd configure a DLQ on the SQS queue itself
        # or explicitly send to a DLQ here
        self._delete_message(receipt_handle)

    def _poll_messages(self) -> list:
        """Poll messages from SQS queue."""
        try:
            response = self.sqs_client.receive_message(
                QueueUrl=self.queue_url,
                MaxNumberOfMessages=self.max_messages,
                WaitTimeSeconds=self.wait_time_seconds,
                VisibilityTimeout=self.visibility_timeout,
                AttributeNames=["All"],
                MessageAttributeNames=["All"],
            )
            return response.get("Messages", [])
        except Exception as e:
            logger.error(f"Error polling messages from SQS: {e}", exc_info=True)
            return []

    def start(self) -> None:
        """Start the worker polling loop."""
        self._running = True
        logger.info(f"Starting SQS worker for queue: {self.queue_url}")

        consecutive_errors = 0
        max_consecutive_errors = 10
        base_backoff = 1

        while self._running:
            try:
                messages = self._poll_messages()

                if not messages:
                    consecutive_errors = 0
                    continue

                logger.info(f"Received {len(messages)} messages")

                for message in messages:
                    if not self._running:
                        break
                    success = self._process_message(message)
                    if success:
                        consecutive_errors = 0
                    else:
                        consecutive_errors += 1

                if consecutive_errors >= max_consecutive_errors:
                    backoff_time = min(base_backoff * (2 ** (consecutive_errors - max_consecutive_errors)), 60)
                    logger.warning(f"Too many consecutive errors, backing off for {backoff_time}s")
                    time.sleep(backoff_time)

            except KeyboardInterrupt:
                logger.info("Received keyboard interrupt, shutting down...")
                self.stop()
            except Exception as e:
                logger.error(f"Unexpected error in polling loop: {e}", exc_info=True)
                consecutive_errors += 1
                time.sleep(min(base_backoff * (2 ** consecutive_errors), 60))

    def stop(self) -> None:
        """Stop the worker."""
        logger.info("Stopping SQS worker...")
        self._running = False


